 13→const DEFAULT_SERVER_URL = "http://localhost:3000";
 14→
 15→export async function runInit(): Promise<void> {
 16→  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 17→  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 18→
 19→  const gitRoot = findGitRoot(process.cwd());
 20→  if (!gitRoot) {
 21→    console.error("Not inside a git repository. Run brain init from a project directory.");
 22→    process.exit(1);
 23→  }
 24→
 25→  if (!workspaceId) {
 26→    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 27→    console.error("Find it in the Brain web UI or the database.");
 28→    process.exit(1);
 29→  }
 30→
 31→  console.log("Brain Init\n──────────\n");
 32→
 33→  // Step 1: Auth
 34→  await setupAuth(serverUrl, workspaceId, gitRoot);
 35→
 36→  // Step 2: .mcp.json
 37→  await setupMcpJson(gitRoot);
 38→
 39→  // Step 3: .claude/settings.json hooks
 40→  await setupClaudeHooks(gitRoot);
 41→
 42→  // Step 4: CLAUDE.md
 43→  await setupClaudeMd(gitRoot);
 44→
 45→  // Step 5: Commands
 46→  await setupCommands(gitRoot);
 47→
 48→  // Step 6: Git hooks
 49→  installGitHooks(gitRoot);
 50→
 51→  console.log(`\nDone. Restart Claude Code to activate.`);
 52→}
 53→
 54→// ---------------------------------------------------------------------------
 55→// Step 1: Auth (OAuth 2.1 PKCE)
 56→// ---------------------------------------------------------------------------
 57→
 58→const DEFAULT_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
 59→
 60→function base64url(buf: Buffer): string {
 61→  return buf.toString("base64url");
 62→}
 63→
 64→function generatePkce(): { verifier: string; challenge: string } {
 65→  const verifier = base64url(randomBytes(32));
 66→  const challenge = base64url(createHash("sha256").update(verifier).digest());
 67→  return { verifier, challenge };
 68→}
 69→
 70→export async function setupAuth(
 71→  serverUrl: string,
 72→  workspaceId: string,
 73→  gitRoot: string,
 74→  options?: { openUrl?: (url: string) => void },
 75→): Promise<void> {
 76→  const global = await loadGlobalConfig();
 77→  const existing = global?.repos[gitRoot];
 78→  if (existing && existing.workspace === workspaceId && existing.access_token) {
 79→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 80→    return;
 81→  }
 82→
 83→  // 1. Verify workspace exists
 84→  try {
 85→    await BrainHttpClient.listProjects(serverUrl, workspaceId);
 86→  } catch {
 87→    console.error(`Workspace ${workspaceId} not found on ${serverUrl}`);
 88→    process.exit(1);
 89→  }
 90→
 91→  // 2. Dynamic Client Registration
 92→  const dcrRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
 93→    method: "POST",
 94→    headers: { "Content-Type": "application/json" },
 95→    body: JSON.stringify({
 96→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
 97→      redirect_uris: ["http://127.0.0.1/callback"],
 98→      grant_types: ["authorization_code", "refresh_token"],
 99→      response_types: ["code"],
100→      token_endpoint_auth_method: "none",
101→    }),
102→  });
103→  if (!dcrRes.ok) {
104→    throw new Error(`Client registration failed: ${dcrRes.status} ${await dcrRes.text()}`);
105→  }
106→  const { client_id } = await dcrRes.json() as { client_id: string };
107→
108→  // 3. PKCE
109→  const pkce = generatePkce();
110→  const state = base64url(randomBytes(16));
111→
112→  // 4. Start local callback server
113→  const { promise: codePromise, resolve: resolveCode, reject: rejectCode } = Promise.withResolvers<string>();
114→
115→  const callbackServer = Bun.serve({
116→    port: 0,
117→    hostname: "127.0.0.1",
118→    routes: {
119→      "/callback": (request) => {
120→        const url = new URL(request.url);
121→        const code = url.searchParams.get("code");
122→        const returnedState = url.searchParams.get("state");
123→        const error = url.searchParams.get("error");
124→
125→        if (error) {
126→          rejectCode(new Error(`OAuth error: ${error}`));
127→          return new Response("<html><body><h1>Authentication failed</h1><p>You can close this tab.</p></body></html>", {
128→            headers: { "Content-Type": "text/html" },
129→          });
130→        }
131→        if (returnedState !== state) {
132→          rejectCode(new Error("state mismatch"));
133→          return new Response("<html><body><h1>State mismatch</h1></body></html>", {
134→            headers: { "Content-Type": "text/html" },
135→          });
136→        }
137→        if (!code) {
138→          rejectCode(new Error("no code returned"));
139→          return new Response("<html><body><h1>No authorization code</h1></body></html>", {
140→            headers: { "Content-Type": "text/html" },
141→          });
142→        }
143→
144→        resolveCode(code);
145→        return new Response("<html><body><h1>Authenticated!</h1><p>You can close this tab and return to the terminal.</p></body></html>", {
146→          headers: { "Content-Type": "text/html" },
147→        });
148→      },
149→    },
150→  });
151→
152→  const redirectUri = `http://127.0.0.1:${callbackServer.port}/callback`;
153→
154→  // Update redirect_uris with actual port (re-register)
155→  const dcrUpdateRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
156→    method: "POST",
157→    headers: { "Content-Type": "application/json" },
158→    body: JSON.stringify({
159→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
160→      redirect_uris: [redirectUri],
161→      grant_types: ["authorization_code", "refresh_token"],
162→      response_types: ["code"],
163→      token_endpoint_auth_method: "none",
164→    }),
165→  });
166→  if (!dcrUpdateRes.ok) {
167→    callbackServer.stop();
168→    throw new Error(`Client re-registration failed: ${dcrUpdateRes.status} ${await dcrUpdateRes.text()}`);
169→  }
170→  const dcrUpdate = await dcrUpdateRes.json() as { client_id: string };
171→  const actualClientId = dcrUpdate.client_id;
172→
173→  // 5. Open browser
174→  const authUrl = new URL(`${serverUrl}/api/auth/oauth2/authorize`);
175→  authUrl.searchParams.set("client_id", actualClientId);
176→  authUrl.searchParams.set("redirect_uri", redirectUri);
177→  authUrl.searchParams.set("response_type", "code");
178→  authUrl.searchParams.set("scope", DEFAULT_SCOPES);
179→  authUrl.searchParams.set("code_challenge", pkce.challenge);
180→  authUrl.searchParams.set("code_challenge_method", "S256");
181→  authUrl.searchParams.set("state", state);
182→  // Pass resource so better-auth issues a JWT access token (not opaque)
183→  authUrl.searchParams.set("resource", `${serverUrl}/api/auth`);
184→
185→  console.log("Opening browser for authentication...");
186→  console.log(`If the browser doesn't open, visit: ${authUrl.toString()}\n`);
187→
188→  const openUrl = options?.openUrl ?? ((url: string) => {
189→    const openCmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
190→    Bun.spawn([openCmd, url], { stdout: "ignore", stderr: "ignore" });
191→  });
192→  openUrl(authUrl.toString());
193→
194→  // 6. Wait for callback
195→  let code: string;
196→  try {
197→    code = await codePromise;
198→  } catch (error) {
199→    callbackServer.stop();
200→    throw error;
201→  }
202→
203→  // 7. Exchange code for tokens
204→  const tokenRes = await fetch(`${serverUrl}/api/auth/oauth2/token`, {
205→    method: "POST",
206→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
207→    body: new URLSearchParams({
208→      grant_type: "authorization_code",
209→      code,
210→      redirect_uri: redirectUri,
211→      client_id: actualClientId,
212→      code_verifier: pkce.verifier,
213→      resource: serverUrl,
214→    }),
215→  });
216→
217→  callbackServer.stop();
218→
219→  if (!tokenRes.ok) {
220→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
221→  }
222→
223→  const tokens = await tokenRes.json() as {
224→    access_token: string;
225→    refresh_token: string;
226→    expires_in: number;
227→    token_type: string;
228→  };
229→
230→  // 8. Generate DPoP key material for sender-constrained tokens
231→  const dpopMaterial = await generateDPoPKeyMaterial();
232→
233→  // 9. Discover workspace owner identity for intent submission
234→  let identityId: string | undefined;
235→  try {
236→    const identityRes = await fetch(`${serverUrl}/api/auth/identity/${workspaceId}`);
237→    if (identityRes.ok) {
238→      const identityData = await identityRes.json() as { identity_id: string };
239→      identityId = identityData.identity_id;
240→    }
241→  } catch {
242→    // Identity discovery is optional during init — will be retried lazily
243→  }
244→
245→  // 10. Store tokens + DPoP key material
246→  await saveRepoConfig(serverUrl, gitRoot, {
247→    workspace: workspaceId,
248→    client_id: actualClientId,
249→    access_token: tokens.access_token,
250→    refresh_token: tokens.refresh_token,
251→    token_expires_at: Math.floor(Date.now() / 1000) + tokens.expires_in,
252→    dpop_private_jwk: dpopMaterial.privateJwk,
253→    dpop_public_jwk: dpopMaterial.publicJwk,
254→    dpop_thumbprint: dpopMaterial.thumbprint,
255→    identity_id: identityId,
256→  });
257→
258→  console.log(`✓ Auth: OAuth tokens + DPoP key pair saved for ${gitRoot}`);
259→  if (identityId) {
260→    console.log(`✓ Identity: ${identityId}`);
261→  }
262→}
