265→// Step 2: .mcp.json
266→// ---------------------------------------------------------------------------
267→
268→export async function setupMcpJson(gitRoot: string): Promise<void> {
269→  const mcpPath = join(gitRoot, ".mcp.json");
270→  const file = Bun.file(mcpPath);
271→  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
272→
273→  if (await file.exists()) {
274→    try {
275→      mcp = await file.json();
276→      mcp.mcpServers ??= {};
277→    } catch {
278→      // Corrupted file — overwrite
279→    }
280→  }
281→
282→  mcp.mcpServers.brain = { command: "brain", args: ["mcp"] };
283→  await Bun.write(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
284→  console.log("✓ MCP: .mcp.json updated");
285→}
