287→// ---------------------------------------------------------------------------
288→// Step 3: .claude/settings.json hooks
289→// ---------------------------------------------------------------------------
290→
291→type HookEntry = { type: string; command?: string; prompt?: string };
292→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
293→
294→export async function setupClaudeHooks(gitRoot: string): Promise<void> {
295→  const claudeDir = join(gitRoot, ".claude");
296→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
297→
298→  const settingsPath = join(claudeDir, "settings.json");
299→  const file = Bun.file(settingsPath);
300→  let settings: Record<string, unknown> = {};
301→
302→  if (await file.exists()) {
303→    try {
304→      settings = await file.json();
305→    } catch {
306→      // Corrupted — start fresh
307→    }
308→  }
309→
310→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
311→  let added = 0;
312→
313→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
314→    hooks[event] ??= [];
315→
316→    const hasBrain = hooks[event].some((group) =>
317→      group.hooks?.some(
318→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
319→      ),
320→    );
321→
322→    if (!hasBrain) {
323→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
324→      added++;
325→    }
326→  }
327→
328→  settings.hooks = hooks;
329→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
330→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
331→}
