333→// ---------------------------------------------------------------------------
334→// Step 4: CLAUDE.md
335→// ---------------------------------------------------------------------------
336→
337→export const MARKER_START = "<!-- brain-plugin-start -->";
338→export const MARKER_END = "<!-- brain-plugin-end -->";
339→
340→export async function setupClaudeMd(gitRoot: string): Promise<void> {
341→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
342→  const file = Bun.file(claudeMdPath);
343→  let content = "";
344→
345→  if (await file.exists()) {
346→    content = await file.text();
347→  }
348→
349→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
350→
351→  const startIdx = content.indexOf(MARKER_START);
352→  const endIdx = content.indexOf(MARKER_END);
353→
354→  if (startIdx !== -1 && endIdx !== -1) {
355→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
356→  } else {
357→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
358→    content = content + separator + brainBlock + "\n";
359→  }
360→
361→  await Bun.write(claudeMdPath, content);
362→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
363→}
