369→export function installGitHooks(gitRoot?: string): void {
370→  const root = gitRoot ?? findGitRoot(process.cwd());
371→  if (!root) {
372→    console.log("  No .git directory found — skipping git hook installation.");
373→    return;
374→  }
375→
376→  const hooksDir = join(root, ".git", "hooks");
377→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
378→
379→  const preCommitPath = join(hooksDir, "pre-commit");
380→  const postCommitPath = join(hooksDir, "post-commit");
381→  const preCommitScript = `#!/bin/sh
382→# Brain pre-commit hook: check for task completion and unlogged decisions
383→brain check-commit
384→`;
385→  const postCommitScript = `#!/bin/sh
386→# Brain post-commit hook: fire-and-forget commit-check
387→brain commit-check &
388→exit 0
389→`;
390→
391→  if (!existsSync(preCommitPath)) {
392→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
393→    console.log("✓ Git: pre-commit hook installed");
394→  } else {
395→    console.log("✓ Git: pre-commit hook already exists");
396→  }
397→
398→  // Remove legacy Brain post-commit hook, then install new one
399→  if (existsSync(postCommitPath)) {
400→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
401→    const isLegacyBrain =
402→      postCommitContent.includes("Brain post-commit hook") &&
403→      postCommitContent.includes("brain log-commit");
404→    const isCurrentBrain =
405→      postCommitContent.includes("Brain post-commit hook") &&
406→      postCommitContent.includes("brain commit-check");
407→    if (isLegacyBrain) {
408→      unlinkSync(postCommitPath);
409→      console.log("  Removed legacy Brain post-commit hook");
410→    } else if (isCurrentBrain) {
411→      console.log("✓ Git: post-commit hook already exists");
412→      return;
413→    } else {
414→      // Non-brain hook — leave it alone
415→      console.log("✓ Git: post-commit hook already exists (non-brain)");
416→      return;
417→    }
418→  }
419→
420→  writeFileSync(postCommitPath, postCommitScript, { mode: 0o755 });
421→  console.log("✓ Git: post-commit hook installed");
422→}
423→
424→export async function setupCommands(gitRoot: string): Promise<void> {
425→  const commandsDir = join(gitRoot, ".claude", "commands");
426→  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
427→
428→  let count = 0;
429→  for (const [filename, content] of Object.entries(BRAIN_COMMANDS)) {
430→    await Bun.write(join(commandsDir, filename), content + "\n");
431→    count++;
432→  }
433→
434→  console.log(`✓ Commands: ${count} slash commands installed to .claude/commands/`);
435→}
