 70→  private async ensureDPoPKeyMaterial(): Promise<void> {
 71→    if (this.dpopPrivateJwk && this.dpopPublicJwk && this.dpopThumbprint) return;
 72→
 73→    const material = await generateDPoPKeyMaterial();
 74→    this.dpopPrivateJwk = material.privateJwk;
 75→    this.dpopPublicJwk = material.publicJwk;
 76→    this.dpopThumbprint = material.thumbprint;
 77→    await this.persistDPoPState();
 78→  }
