 84→  private async ensureIdentity(): Promise<void> {
 85→    if (this.identityId) return;
 86→
 87→    const res = await fetch(`${this.baseUrl}/api/auth/identity/${this.workspaceId}`);
 88→    if (!res.ok) {
 89→      throw new Error(`Identity discovery failed: ${res.status}. Run 'brain init' to re-authenticate.`);
