 96→  // ---------------------------------------------------------------------------
 97→  // DPoP token acquisition via intent submission + token endpoint
 98→  // ---------------------------------------------------------------------------
 99→
100→  private async ensureDPoPToken(): Promise<void> {
101→    // Refresh 30 seconds before expiry
102→    if (
103→      this.dpopAccessToken &&
104→      this.dpopTokenExpiresAt &&
105→      Date.now() < (this.dpopTokenExpiresAt - 30) * 1000
106→    ) {
107→      return;
108→    }
109→
110→    await this.ensureDPoPKeyMaterial();
111→    await this.ensureIdentity();
112→
113→    // Step 1: Submit intent with broad authorization_details
114→    const intentRes = await fetch(`${this.baseUrl}/api/auth/intents`, {
115→      method: "POST",
116→      headers: { "Content-Type": "application/json" },
117→      body: JSON.stringify({
118→        workspace_id: this.workspaceId,
119→        identity_id: this.identityId,
120→        authorization_details: CLI_AUTHORIZATION_DETAILS,
121→        dpop_jwk_thumbprint: this.dpopThumbprint,
122→        goal: "CLI workspace access",
123→        reasoning: "Brain CLI requires broad MCP access for workspace operations",
124→      }),
125→    });
126→
127→    if (!intentRes.ok) {
128→      const text = await intentRes.text();
129→      throw new Error(`Intent submission failed: ${intentRes.status} ${text}. Run 'brain init' to re-authenticate.`);
130→    }
131→
132→    const intentData = await intentRes.json() as {
133→      intent_id: string;
134→      status: string;
135→    };
136→
137→    if (intentData.status !== "authorized") {
138→      throw new Error(
139→        `Intent not auto-approved (status: ${intentData.status}). ` +
140→        "CLI requires auto-approval for broad read/write access. Check identity permissions.",
141→      );
142→    }
143→
144→    // Step 2: Exchange intent for DPoP-bound token
145→    const tokenUrl = `${this.baseUrl}/api/auth/token`;
146→    const dpopProof = await createDPoPProof(
147→      this.dpopPrivateJwk!,
148→      this.dpopPublicJwk!,
149→      "POST",
150→      tokenUrl,
151→    );
152→
153→    const tokenRes = await fetch(tokenUrl, {
154→      method: "POST",
155→      headers: {
156→        "Content-Type": "application/json",
157→        DPoP: dpopProof,
158→      },
159→      body: JSON.stringify({
160→        grant_type: "urn:brain:intent-authorization",
161→        intent_id: intentData.intent_id,
162→        authorization_details: CLI_AUTHORIZATION_DETAILS,
163→      }),
164→    });
165→
166→    if (!tokenRes.ok) {
167→      const text = await tokenRes.text();
168→      throw new Error(`Token exchange failed: ${tokenRes.status} ${text}`);
169→    }
170→
171→    const tokenData = await tokenRes.json() as {
172→      access_token: string;
173→      token_type: string;
174→      expires_in: number;
175→    };
176→
177→    this.dpopAccessToken = tokenData.access_token;
178→    this.dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenData.expires_in;
179→    await this.persistDPoPState();
180→  }
181→
182→  // ---------------------------------------------------------------------------
183→  // Per-request DPoP headers
184→  // ---------------------------------------------------------------------------
185→
186→  private async dpopHeaders(method: string, url: string): Promise<Record<string, string>> {
187→    await this.ensureDPoPToken();
188→
189→    const proof = await createDPoPProof(
190→      this.dpopPrivateJwk!,
191→      this.dpopPublicJwk!,
192→      method,
193→      url,
194→    );
195→
196→    return {
197→      "Content-Type": "application/json",
198→      Authorization: `DPoP ${this.dpopAccessToken}`,
199→      DPoP: proof,
200→    };
201→  }
