203→  // ---------------------------------------------------------------------------
204→  // Legacy Bearer headers (for non-MCP endpoints)
205→  // ---------------------------------------------------------------------------
206→
207→  private async refreshBearerTokenIfNeeded(): Promise<void> {
208→    if (Date.now() < (this.tokenExpiresAt - 60) * 1000) return;
209→
210→    const res = await fetch(`${this.baseUrl}/api/auth/oauth2/token`, {
211→      method: "POST",
212→      headers: { "Content-Type": "application/x-www-form-urlencoded" },
213→      body: new URLSearchParams({
214→        grant_type: "refresh_token",
215→        refresh_token: this.refreshToken,
216→        client_id: this.clientId,
217→        resource: this.baseUrl,
218→      }),
219→    });
220→
221→    if (!res.ok) {
222→      throw new Error(`Token refresh failed: ${res.status}. Run 'brain init' to re-authenticate.`);
223→    }
224→
225→    const data = await res.json() as {
226→      access_token: string;
227→      refresh_token?: string;
228→      expires_in: number;
229→    };
230→
231→    this.accessToken = data.access_token;
232→    if (data.refresh_token) this.refreshToken = data.refresh_token;
233→    this.tokenExpiresAt = Math.floor(Date.now() / 1000) + data.expires_in;
234→
235→    const gitRoot = findGitRoot(process.cwd());
236→    const global = await loadGlobalConfig();
237→    if (global && gitRoot && global.repos[gitRoot]) {
238→      global.repos[gitRoot].access_token = this.accessToken;
239→      if (data.refresh_token) global.repos[gitRoot].refresh_token = this.refreshToken;
240→      global.repos[gitRoot].token_expires_at = this.tokenExpiresAt;
241→      await saveGlobalConfig(global);
242→    }
243→  }
