245→  // ---------------------------------------------------------------------------
246→  // Config persistence
247→  // ---------------------------------------------------------------------------
248→
249→  private async persistDPoPState(): Promise<void> {
250→    const gitRoot = findGitRoot(process.cwd());
251→    const global = await loadGlobalConfig();
252→    if (global && gitRoot && global.repos[gitRoot]) {
253→      const repo = global.repos[gitRoot];
254→      repo.dpop_private_jwk = this.dpopPrivateJwk;
255→      repo.dpop_public_jwk = this.dpopPublicJwk;
256→      repo.dpop_thumbprint = this.dpopThumbprint;
257→      repo.dpop_access_token = this.dpopAccessToken;
258→      repo.dpop_token_expires_at = this.dpopTokenExpiresAt;
259→      repo.identity_id = this.identityId;
260→      await saveGlobalConfig(global);
261→    }
262→  }
