 1→/**
 2→ * Intelligence Config Loader
 3→ *
 4→ * Reads proxy_intelligence_config per workspace from SurrealDB.
 5→ * Falls back to env-var defaults when no config exists.
 6→ *
 7→ * Port: (workspaceId, Surreal) -> Promise<IntelligenceConfig>
 8→ * Pure mapping: (RawRow | undefined) -> IntelligenceConfig
 9→ */
10→
11→import { RecordId } from "surrealdb";
12→import type { Surreal } from "surrealdb";
13→import { logWarn } from "../http/observability";
14→
15→// ---------------------------------------------------------------------------
16→// Types
17→// ---------------------------------------------------------------------------
18→
19→export type RawIntelligenceConfigRow = {
20→  readonly context_injection_enabled: boolean;
21→  readonly context_injection_token_budget: number;
22→  readonly context_injection_cache_ttl_seconds: number;
23→  readonly context_injection_tier: string;
24→  readonly contradiction_detection_enabled: boolean;
25→  readonly contradiction_tier1_threshold: number;
26→  readonly contradiction_tier2_confidence_min: number;
27→};
28→
29→export type IntelligenceConfig = {
30→  readonly contextInjectionEnabled: boolean;
31→  readonly contextInjectionTokenBudget: number;
32→  readonly contextInjectionCacheTtlSeconds: number;
33→  readonly contextInjectionTier: string;
34→};
35→
36→// ---------------------------------------------------------------------------
37→// Defaults (env-var fallback)
38→// ---------------------------------------------------------------------------
39→
40→const DEFAULTS: IntelligenceConfig = {
41→  contextInjectionEnabled: false,
42→  contextInjectionTokenBudget: 1000,
43→  contextInjectionCacheTtlSeconds: 300,
44→  contextInjectionTier: "fast",
45→};
46→
47→// ---------------------------------------------------------------------------
48→// Pure mapping: DB row -> domain config
49→// ---------------------------------------------------------------------------
50→
51→export function resolveIntelligenceConfig(
52→  row: RawIntelligenceConfigRow | undefined,
53→): IntelligenceConfig {
54→  if (!row) return DEFAULTS;
55→
56→  return {
57→    contextInjectionEnabled: row.context_injection_enabled,
58→    contextInjectionTokenBudget: row.context_injection_token_budget,
59→    contextInjectionCacheTtlSeconds: row.context_injection_cache_ttl_seconds,
60→    contextInjectionTier: row.context_injection_tier,
61→  };
62→}
63→
64→// ---------------------------------------------------------------------------
65→// DB loader (adapter boundary)
66→// ---------------------------------------------------------------------------
67→
68→export async function loadIntelligenceConfig(
69→  surreal: Surreal,
70→  workspaceId: string,
71→): Promise<IntelligenceConfig> {
72→  try {
73→    const workspaceRecord = new RecordId("workspace", workspaceId);
74→    const results = await surreal.query<[RawIntelligenceConfigRow[]]>(
75→      `SELECT
76→        context_injection_enabled,
77→        context_injection_token_budget,
78→        context_injection_cache_ttl_seconds,
79→        context_injection_tier,
80→        contradiction_detection_enabled,
81→        contradiction_tier1_threshold,
82→        contradiction_tier2_confidence_min
83→      FROM proxy_intelligence_config
84→      WHERE workspace = $ws
85→      LIMIT 1;`,
86→      { ws: workspaceRecord },
87→    );
88→
89→    const row = results[0]?.[0];
90→    return resolveIntelligenceConfig(row);
91→  } catch (error) {
92→    logWarn("proxy.intelligence_config.load_failed", "Failed to load intelligence config, using defaults", {
93→      workspace_id: workspaceId,
94→      error: String(error),
95→    });
96→    return DEFAULTS;
97→  }
98→}
