  1→import { existsSync, mkdirSync, statSync } from "node:fs";
  2→import { join, dirname, resolve } from "node:path";
  3→import { homedir } from "node:os";
  4→
  5→function getBrainDir() { return process.env.BRAIN_CONFIG_DIR ?? join(homedir(), ".brain"); }
  6→function getConfigPath() { return join(getBrainDir(), "config.json"); }
  7→
  8→/** Resolved config for a single repo — shape consumed by BrainHttpClient and all commands. */
  9→export type BrainConfig = {
 10→  server_url: string;
 11→  workspace: string;
 12→  client_id: string;
 13→  access_token: string;
 14→  refresh_token: string;
 15→  token_expires_at: number;
 16→  /** DPoP key material for sender-constrained tokens */
 17→  dpop_private_jwk?: JsonWebKey;
 18→  dpop_public_jwk?: JsonWebKey;
 19→  dpop_thumbprint?: string;
 20→  /** DPoP-bound access token for MCP endpoints */
 21→  dpop_access_token?: string;
 22→  dpop_token_expires_at?: number;
 23→  /** Identity for intent submission */
 24→  identity_id?: string;
 25→};
 26→
 27→/** Per-repo auth entry in ~/.brain/config.json */
 28→export type RepoConfig = {
 29→  workspace: string;
 30→  client_id: string;
 31→  access_token: string;
 32→  refresh_token: string;
 33→  token_expires_at: number;
 34→  dpop_private_jwk?: JsonWebKey;
 35→  dpop_public_jwk?: JsonWebKey;
 36→  dpop_thumbprint?: string;
 37→  dpop_access_token?: string;
 38→  dpop_token_expires_at?: number;
 39→  identity_id?: string;
 40→};
 41→
 42→/** Root shape of ~/.brain/config.json */
 43→export type BrainGlobalConfig = {
 44→  server_url: string;
 45→  repos: Record<string, RepoConfig>;
 46→};
 47→
 48→// ---------------------------------------------------------------------------
 49→// Git root
 50→// ---------------------------------------------------------------------------
 51→
 52→/**
 53→ * Find the main repository root from any path, including worktrees.
 54→ *
 55→ * In a regular repo, `.git` is a directory → that dir is the root.
 56→ * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 57→ * We follow the pointer back to the main repo so all worktrees share one config key.
 58→ */
 59→export function findGitRoot(from: string): string | undefined {
 60→  let dir = from;
 61→  while (dir !== "/") {
 62→    const gitPath = join(dir, ".git");
 63→    if (existsSync(gitPath)) {
 64→      if (statSync(gitPath).isFile()) {
 65→        return resolveWorktreeMainRoot(gitPath) ?? dir;
 66→      }
 67→      return dir;
 68→    }
 69→    dir = dirname(dir);
 70→  }
 71→  return undefined;
 72→}
 73→
 74→/** Read a worktree .git file and resolve to the main repo root. */
 75→function resolveWorktreeMainRoot(gitFile: string): string | undefined {
 76→  try {
 77→    const content = Bun.file(gitFile).textSync().trim();
 78→    const match = content.match(/^gitdir:\s*(.+)$/);
 79→    if (!match) return undefined;
 80→
 81→    const gitdir = resolve(dirname(gitFile), match[1]);
 82→    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
 83→    return dirname(dotGit);
 84→  } catch {
 85→    return undefined;
 86→  }
 87→}
 88→
 89→// ---------------------------------------------------------------------------
 90→// Global config (~/.brain/config.json)
 91→// ---------------------------------------------------------------------------
 92→
 93→function ensureBrainDir(): void {
 94→  const dir = getBrainDir();
 95→  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
 96→}
 97→
 98→export async function loadGlobalConfig(): Promise<BrainGlobalConfig | undefined> {
 99→  const file = Bun.file(getConfigPath());
100→  if (!(await file.exists())) return undefined;
101→  try {
102→    return await file.json() as BrainGlobalConfig;
103→  } catch {
104→    return undefined;
105→  }
106→}
107→
108→export async function saveGlobalConfig(config: BrainGlobalConfig): Promise<void> {
109→  ensureBrainDir();
110→  await Bun.write(getConfigPath(), JSON.stringify(config, null, 2) + "\n");
111→}
112→
113→/** Upsert a repo entry in the global config. Creates the file if needed. */
114→export async function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): Promise<void> {
115→  const global = (await loadGlobalConfig()) ?? { server_url: serverUrl, repos: {} };
116→  global.server_url = serverUrl;
117→  global.repos[gitRoot] = repo;
118→  await saveGlobalConfig(global);
119→}
120→
121→// ---------------------------------------------------------------------------
122→// Resolved config (what consumers use)
123→// ---------------------------------------------------------------------------
124→
125→/** Resolve BrainConfig for the current repo from ~/.brain/config.json.
126→ *  The server URL can be overridden via the BRAIN_SERVER_URL env var. */
127→export async function loadConfig(): Promise<BrainConfig | undefined> {
128→  const gitRoot = findGitRoot(process.cwd());
129→  const global = await loadGlobalConfig();
130→  if (global && gitRoot && global.repos[gitRoot]) {
131→    const repo = global.repos[gitRoot];
132→    const serverUrl = process.env.BRAIN_SERVER_URL ?? global.server_url;
133→    return {
134→      server_url: serverUrl,
135→      workspace: repo.workspace,
136→      client_id: repo.client_id,
137→      access_token: repo.access_token,
138→      refresh_token: repo.refresh_token,
139→      token_expires_at: repo.token_expires_at,
140→      dpop_private_jwk: repo.dpop_private_jwk,
141→      dpop_public_jwk: repo.dpop_public_jwk,
142→      dpop_thumbprint: repo.dpop_thumbprint,
143→      dpop_access_token: repo.dpop_access_token,
144→      dpop_token_expires_at: repo.dpop_token_expires_at,
145→      identity_id: repo.identity_id,
146→    };
147→  }
148→  return undefined;
149→}
150→
151→export async function requireConfig(): Promise<BrainConfig> {
152→  const config = await loadConfig();
153→  if (!config) {
154→    console.error("Brain not configured. Run: brain init");
155→    process.exit(1);
156→  }
157→  return config;
158→}
