315→// ---------------------------------------------------------------------------
316→// Embedding Helper (adapter boundary)
317→// ---------------------------------------------------------------------------
318→
319→async function embedUserMessage(
320→  embeddingModel: ServerDependencies["embeddingModel"],
321→  embeddingDimension: number,
322→  text: string,
323→): Promise<number[] | undefined> {
324→  try {
325→    const { embed } = await import("ai");
326→    const normalized = text.trim();
327→    if (normalized.length === 0) return undefined;
328→
329→    const result = await embed({
330→      model: embeddingModel,
331→      value: normalized,
332→    });
333→
334→    if (result.embedding.length !== embeddingDimension) return undefined;
335→    return result.embedding;
336→  } catch {
337→    return undefined;
338→  }
339→}
